//
//  AircraftIcon.swift
//  Airline Architect — Phase 2
//
//  Real Figma-sourced vector aircraft icons, one per body-type tier, ported
//  from AIRCRAFT_ICONS in the prototype (raw `<path d>` data, not raster —
//  so the fill colour can be set per flight-phase at render time). Each icon
//  is recentred on its viewBox and scaled to its own `targetLength` (NOT a
//  shared constant), preserving the real RJ < narrowbody < 2-engine <
//  4-engine size hierarchy across icons with different native viewBoxes.
//  Nose is authored toward +x, so rotating by heading points it correctly.
//

import SwiftUI

struct AircraftIcon {
    let path: Path
    let center: CGPoint
    let scale: CGFloat

    private init(pathData: String, viewBoxWidth: CGFloat, viewBoxHeight: CGFloat, targetLength: CGFloat) {
        self.path = SVGPath.parse(pathData)
        self.center = CGPoint(x: viewBoxWidth / 2, y: viewBoxHeight / 2)
        self.scale = targetLength / viewBoxWidth
    }

    /// Precomputed once (static) — parsing the paths per frame would be wasteful.
    static let byBodyType: [BodyType: AircraftIcon] = [
        .turboprop:       AircraftIcon(pathData: regionalJetPath, viewBoxWidth: 80, viewBoxHeight: 80, targetLength: 8.5),
        .widebody4Engine: AircraftIcon(pathData: widebody4Path, viewBoxWidth: 151, viewBoxHeight: 150, targetLength: 19.9),
        .widebody2Engine: AircraftIcon(pathData: widebody2Path, viewBoxWidth: 163, viewBoxHeight: 150, targetLength: 17.1),
        .narrowbody:      AircraftIcon(pathData: narrowbodyPath, viewBoxWidth: 109, viewBoxHeight: 100, targetLength: 12.5),
        .regionalJet:     AircraftIcon(pathData: regionalJetPath, viewBoxWidth: 80, viewBoxHeight: 80, targetLength: 9.9),
    ]

